'use client';

import { MessageSquare, Sparkles, Network } from 'lucide-react';
import { useState } from 'react';

import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { useI18n } from '@/core/i18n/hooks';
import { useAiPanelStore } from '@/core/novel';

import { AiChatView } from './ai/AiChatView';
import { ContextInspector } from './ai/ContextInspector';

export function AiPanel({ novelId }: { novelId: string }) {
  const { t } = useI18n();
  const { activeTab, setActiveTab } = useAiPanelStore();

  return (
    <div className="flex h-full flex-col">
      <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as any)} className="flex h-full flex-col">
        <TabsList className="grid w-full grid-cols-3 rounded-none border-b bg-muted/50">
          <TabsTrigger value="chat" className="gap-1.5 data-[state=active]:bg-background">
            <MessageSquare className="h-3.5 w-3.5" />
            <span className="hidden sm:inline">{t.novel.chat}</span>
          </TabsTrigger>
          <TabsTrigger value="generate" className="gap-1.5 data-[state=active]:bg-background">
            <Sparkles className="h-3.5 w-3.5" />
            <span className="hidden sm:inline">Generate</span>
          </TabsTrigger>
          <TabsTrigger value="context" className="gap-1.5 data-[state=active]:bg-background">
            <Network className="h-3.5 w-3.5" />
            <span className="hidden sm:inline">{t.novel.contextEntities}</span>
          </TabsTrigger>
        </TabsList>
        <TabsContent value="chat" className="flex-1 overflow-hidden m-0">
          <AiChatView novelId={novelId} />
        </TabsContent>
        <TabsContent value="generate" className="flex-1 overflow-hidden m-0">
          <div className="flex h-full flex-col items-center justify-center gap-3 text-muted-foreground">
            <Sparkles className="h-10 w-10 opacity-30" />
            <p className="text-sm">AI Generation tools coming soon</p>
          </div>
        </TabsContent>
        <TabsContent value="context" className="flex-1 overflow-hidden m-0">
          <ContextInspector />
        </TabsContent>
      </Tabs>
    </div>
  );
}

'use client';

import CharacterCount from '@tiptap/extension-character-count';
import { useEditor, EditorContent } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import React, { useEffect, useRef } from 'react';

import { useNovelStore, useAiPanelStore } from '@/core/novel';
import { useNovelQuery, useUpdateChapterMutation } from '@/core/novel/queries';
import { useDebounce } from '@/core/novel/useDebounce';
import { cn } from '@/lib/utils';

import { ChapterInfoCard } from './editor/ChapterInfoCard';
import { EditorToolbar } from './EditorToolbar';

export function NovelEditor({ novelId }: { novelId: string }) {
  const { activeChapterId, dirtyContent, setDirtyContent } = useNovelStore();
  const aiStream = useAiPanelStore((s) => s.aiStream);
  const { data: novelData, isLoading } = useNovelQuery(novelId);
  const updateChapterMutation = useUpdateChapterMutation();
  const previousChapterRef = useRef<{ id: string; content: string | null }>({ id: '', content: null });

  const { chapters = [] } = novelData || {};
  const activeChapter = chapters.find((ch) => ch.id === activeChapterId);

  useEffect(() => {
    previousChapterRef.current = { id: activeChapterId || '', content: dirtyContent };
  });

  const debouncedSave = useDebounce(
    (content: string) => {
      if (activeChapterId) {
        updateChapterMutation.mutate({ chapterId: activeChapterId, content });
        setDirtyContent(null);
      }
    },
    1000
  );

  useEffect(() => {
    if (dirtyContent !== null) {
      debouncedSave(dirtyContent);
    }
  }, [dirtyContent, debouncedSave]);

  useEffect(() => {
    const previousChapter = previousChapterRef.current;
    if (previousChapter && previousChapter.content !== null && previousChapter.id) {
      debouncedSave.cancel();
      updateChapterMutation.mutate({
        chapterId: previousChapter.id,
        content: previousChapter.content,
      });
      setDirtyContent(null);
    }

    if (editor) {
      const newContent = chapters.find((ch) => ch.id === activeChapterId)?.content || '';
      if (editor.getHTML() !== newContent) {
        editor.commands.setContent(newContent, { emitUpdate: false });
      }
    }
  }, [activeChapterId]);

  const editor = useEditor({
    immediatelyRender: false,
    extensions: [
      StarterKit.configure({
        heading: { levels: [1, 2, 3] },
        bulletList: { keepMarks: true, keepAttributes: false },
        orderedList: { keepMarks: true, keepAttributes: false },
      }),
      CharacterCount.configure({ limit: null }),
    ],
    content: activeChapter?.content || '',
    editorProps: {
      attributes: {
        class: 'prose prose-lg dark:prose-invert max-w-none focus:outline-none leading-relaxed',
      },
    },
    onUpdate: ({ editor }) => {
      if (!aiStream.isStreaming) {
        setDirtyContent(editor.getHTML());
      }
    },
  });

  const wasStreamingRef = useRef(false);
  useEffect(() => {
    if (wasStreamingRef.current && !aiStream.isStreaming && editor) {
      setDirtyContent(editor.getHTML());
    }
    wasStreamingRef.current = aiStream.isStreaming;
  }, [aiStream.isStreaming, editor, setDirtyContent]);

  useEffect(() => {
    if (!editor) return;
    if (aiStream.isStreaming && aiStream.latestChunk) {
      const formattedChunk = aiStream.latestChunk.replace(/\n/g, '<br/>');
      editor.chain().setMeta('addToHistory', false).insertContent(formattedChunk).scrollIntoView().run();
    }
  }, [aiStream.seq, aiStream.isStreaming, aiStream.latestChunk, editor]);

  if (isLoading) {
    return (
      <div className="flex h-full items-center justify-center text-muted-foreground">
        Loading...
      </div>
    );
  }

  if (!novelData) {
    return (
      <div className="flex h-full items-center justify-center text-muted-foreground">
        No novel data found
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col overflow-hidden bg-background">
      <EditorToolbar editor={editor} novelId={novelId} />
      <div className="flex-1 overflow-hidden">
        <div className="w-full max-w-[95%] mx-auto px-4 sm:px-8 lg:px-12 py-6 sm:py-8 flex flex-col h-full">
          {activeChapter && <ChapterInfoCard chapter={activeChapter} />}
          <div className="editor-area rounded-lg border bg-card p-6 sm:p-8 flex-1 overflow-y-auto">
            <EditorContent editor={editor} />
          </div>
        </div>
      </div>
      {aiStream.isStreaming && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-background/80 backdrop-blur-sm">
          <div className="text-center">
            <div className="text-lg font-medium">AI is writing...</div>
          </div>
        </div>
      )}
      {editor && (
        <div className="flex items-center justify-between border-t px-4 py-2 text-sm text-muted-foreground">
          <span>Words: {editor.storage.characterCount.words()} | Chars: {editor.storage.characterCount.characters()}</span>
        </div>
      )}

    </div>
  );
}

'use client';

import { type Editor } from '@tiptap/react';
import {
  Bold,
  Italic,
  Strikethrough,
  Heading1,
  Heading2,
  Heading3,
  List,
  ListOrdered,
  Quote,
  Undo2,
  Redo2,
  MessageSquare,
  Sparkles,
  PenTool,
  Languages,
  X,
  Search,
} from 'lucide-react';
import { useState, useCallback, useRef } from 'react';
import { toast } from 'sonner';

import { useAiPanelStore, useNovelStore } from '@/core/novel';
import { novelAiService } from '@/core/novel/ai-service';
import { useNovelQuery } from '@/core/novel/queries';
import { cn } from '@/lib/utils';

interface EditorToolbarProps {
  editor: Editor | null;
  novelId: string;
  className?: string;
}

export function EditorToolbar({ editor, novelId, className }: EditorToolbarProps) {
  const { data: novelData } = useNovelQuery(novelId);
  const { activeChapterId } = useNovelStore();
  const { startStreaming, stopStreaming, addChunk, aiStream } = useAiPanelStore();

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const abortRef = useRef<AbortController | null>(null);

  if (!editor) return null;

  const activeChapter = novelData?.chapters?.find((ch) => ch.id === activeChapterId);

  const isAnyPending = aiStream.isStreaming || isAnalyzing;

  const getSelectedText = () => {
    const { from, to } = editor.state.selection;
    return editor.state.doc.textBetween(from, to);
  };

  const getTextBeforeCursor = () => {
    const { from } = editor.state.selection;
    const start = Math.max(0, from - 1000);
    return editor.state.doc.textBetween(start, from);
  };

  const insertAtCursor = (text: string) => {
    const { from, to } = editor.state.selection;
    editor.chain().focus().insertContentAt({ from, to }, text).run();
  };

  const handleReplaceText = async (action: 'polish' | 'expand' | 'condense' | 'rewrite') => {
    const selectedText = getSelectedText();
    if (!selectedText) return;

    const { from, to } = editor.state.selection;

    abortRef.current = new AbortController();
    startStreaming();

    try {
      const result = await novelAiService.chat({
        messages: [
          {
            role: 'system',
            content: getSystemPrompt(action),
          },
          {
            role: 'user',
            content: getUserContent(action, selectedText),
          },
        ],
        novelId,
        stream: true,
      }, {
        onChunk: (chunk) => {
          addChunk(chunk);
        },
        onComplete: (fullText) => {
          if (fullText) {
            editor.chain().focus().insertContentAt({ from, to }, fullText).run();
          }
          stopStreaming();
        },
        onError: (error) => {
          toast.error(`${action} 操作失败`, { description: error.message });
          stopStreaming();
        },
        onAbort: () => {
          stopStreaming();
        },
      });
    } catch (error) {
      if (error instanceof DOMException && error.name === 'AbortError') {
        stopStreaming();
      } else {
        toast.error(`${action} 操作失败`, { description: '请稍后重试' });
        stopStreaming();
      }
    }
  };

  const handleContinueWriting = useCallback(async () => {
    if (!activeChapter || !activeChapterId) return;

    const selectedText = getSelectedText();
    const textBeforeCursor = getTextBeforeCursor();
    const contextText = selectedText || textBeforeCursor;

    if (!contextText.trim()) return;

    abortRef.current = new AbortController();
    startStreaming();

    try {
      const fullContent = activeChapter.content || '';
      const textOnly = fullContent.replace(/<[^>]*>/g, '');

      const prompt = selectedText
        ? contextText
        : `请继续以下章节的内容，保持情节连贯：\n\n${textOnly}`;

      await novelAiService.chat({
        messages: [
          {
            role: 'system',
            content: `你是一个小说续写助手。基于以下上下文信息，继续写故事。保持角色性格一致，情节连贯。
大纲：${activeChapter.description || ''}
原文：${textOnly}`,
          },
          {
            role: 'user',
            content: `请继续以下章节的内容：\n${prompt}`,
          },
        ],
        novelId,
        stream: true,
      }, {
        onChunk: (chunk) => {
          addChunk(chunk);
        },
        onComplete: (fullText) => {
          if (fullText) {
            if (!selectedText) {
              editor.commands.insertContent(fullText);
              editor.commands.focus('end');
            } else {
              editor.chain().focus().insertContent(fullText).run();
            }
          }
          stopStreaming();
        },
        onError: (error) => {
          toast.error('续写失败', { description: error.message });
          stopStreaming();
        },
        onAbort: () => {
          stopStreaming();
        },
        abortSignal: abortRef.current.signal,
      });
    } catch (error) {
      if (!(error instanceof DOMException && error.name === 'AbortError')) {
        toast.error('续写失败', { description: '请稍后重试' });
      }
      stopStreaming();
    }
  }, [activeChapter, activeChapterId, editor, startStreaming, stopStreaming, addChunk]);

  const handleAbort = () => {
    abortRef.current?.abort();
    stopStreaming();
  };

  const handleEntityAnalysis = async () => {
    const selectedText = getSelectedText();
    if (!selectedText) return;

    setIsAnalyzing(true);
    try {
      const entities = await novelAiService.extractEntities(selectedText);
      toast.success('实体分析完成', {
        description: `角色: ${entities.characters?.length || 0}个, 场景: ${entities.settings?.length || 0}个`,
      });
    } catch (error) {
      toast.error('实体分析失败', { description: '请稍后重试' });
    } finally {
      setIsAnalyzing(false);
    }
  };

  const buttons = [
    {
      icon: <Undo2 className="h-4 w-4" />,
      label: 'Undo',
      action: () => editor.chain().focus().undo().run(),
      isActive: false,
    },
    {
      icon: <Redo2 className="h-4 w-4" />,
      label: 'Redo',
      action: () => editor.chain().focus().redo().run(),
      isActive: false,
    },
    { type: 'separator' as const },
    {
      icon: <Bold className="h-4 w-4" />,
      label: 'Bold',
      action: () => editor.chain().focus().toggleBold().run(),
      isActive: editor.isActive('bold'),
    },
    {
      icon: <Italic className="h-4 w-4" />,
      label: 'Italic',
      action: () => editor.chain().focus().toggleItalic().run(),
      isActive: editor.isActive('italic'),
    },
    {
      icon: <Strikethrough className="h-4 w-4" />,
      label: 'Strike',
      action: () => editor.chain().focus().toggleStrike().run(),
      isActive: editor.isActive('strike'),
    },
    { type: 'separator' as const },
    {
      icon: <Heading1 className="h-4 w-4" />,
      label: 'H1',
      action: () => editor.chain().focus().toggleHeading({ level: 1 }).run(),
      isActive: editor.isActive('heading', { level: 1 }),
    },
    {
      icon: <Heading2 className="h-4 w-4" />,
      label: 'H2',
      action: () => editor.chain().focus().toggleHeading({ level: 2 }).run(),
      isActive: editor.isActive('heading', { level: 2 }),
    },
    {
      icon: <Heading3 className="h-4 w-4" />,
      label: 'H3',
      action: () => editor.chain().focus().toggleHeading({ level: 3 }).run(),
      isActive: editor.isActive('heading', { level: 3 }),
    },
    { type: 'separator' as const },
    {
      icon: <List className="h-4 w-4" />,
      label: 'Bullet List',
      action: () => editor.chain().focus().toggleBulletList().run(),
      isActive: editor.isActive('bulletList'),
    },
    {
      icon: <ListOrdered className="h-4 w-4" />,
      label: 'Ordered List',
      action: () => editor.chain().focus().toggleOrderedList().run(),
      isActive: editor.isActive('orderedList'),
    },
    {
      icon: <Quote className="h-4 w-4" />,
      label: 'Blockquote',
      action: () => editor.chain().focus().toggleBlockquote().run(),
      isActive: editor.isActive('blockquote'),
    },
    { type: 'separator' as const },
    {
      icon: <MessageSquare className="h-4 w-4" />,
      label: 'Continue',
      action: handleContinueWriting,
      isActive: false,
      isAi: true as const,
    },
    {
      icon: <Sparkles className="h-4 w-4" />,
      label: 'Polish',
      action: () => handleReplaceText('polish'),
      isActive: false,
      isAi: true as const,
    },
    {
      icon: <PenTool className="h-4 w-4" />,
      label: 'Expand',
      action: () => handleReplaceText('expand'),
      isActive: false,
      isAi: true as const,
    },
    {
      icon: <Languages className="h-4 w-4" />,
      label: 'Condense',
      action: () => handleReplaceText('condense'),
      isActive: false,
      isAi: true as const,
    },
    {
      icon: <Sparkles className="h-4 w-4" />,
      label: 'Rewrite',
      action: () => handleReplaceText('rewrite'),
      isActive: false,
      isAi: true as const,
    },
    {
      icon: <Search className="h-4 w-4" />,
      label: 'Analyze',
      action: handleEntityAnalysis,
      isActive: false,
      isAi: true as const,
    },
  ];

  return (
    <div className={cn('flex flex-wrap items-center gap-1 border-b bg-muted/50 px-3 py-2', className)}>
      {buttons.map((btn, index) =>
        btn.type === 'separator' ? (
          <div key={`sep-${index}`} className="mx-1 h-5 w-px bg-border" />
        ) : (
          <button
            key={btn.label}
            onClick={btn.action}
            disabled={isAnyPending}
            title={btn.label}
            className={cn(
              'flex h-8 w-8 items-center justify-center rounded-md transition-colors hover:bg-accent hover:text-accent-foreground',
              btn.isActive && 'bg-accent text-accent-foreground',
              (btn as any).isAi && 'text-muted-foreground hover:text-foreground',
              isAnyPending && 'opacity-50 cursor-not-allowed'
            )}
          >
            {btn.icon}
          </button>
        )
      )}
      {(aiStream.isStreaming || isAnalyzing) && (
        <button
          onClick={handleAbort}
          title="取消"
          className="flex h-8 w-8 items-center justify-center rounded-md text-red-500 transition-colors hover:bg-red-100 dark:hover:bg-red-900"
        >
          <X className="h-4 w-4" />
        </button>
      )}
    </div>
  );
}

function getSystemPrompt(action: 'polish' | 'expand' | 'condense' | 'rewrite'): string {
  switch (action) {
    case 'polish':
      return '你是一个专业的文字润色助手。改进文字表达的流畅度、用词准确性和文学性，但不要改变原文的核心意思。';
    case 'expand':
      return '你是一个场景扩写助手。将简短的场景描述扩写成详细的叙述，增加细节和情感描写。';
    case 'condense':
      return '你是一个文字精简助手。请将段落精简压缩，保留核心情节和关键信息，去除冗余描写。不要改变原文的核心意思。';
    case 'rewrite':
      return '你是一个文字改写助手。请用更加生动、引人入胜的方式重写以下段落，保持原意不变但提升文学性和可读性。';
    default:
      return '';
  }
}

function getUserContent(action: 'polish' | 'expand' | 'condense' | 'rewrite', text: string): string {
  switch (action) {
    case 'polish':
      return `请润色以下文字：\n${text}`;
    case 'expand':
      return `请扩写以下场景：\n${text}`;
    case 'condense':
      return `请精简以下文字：\n${text}`;
    case 'rewrite':
      return `请重写以下文字：\n${text}`;
    default:
      return '';
  }
}

'use client';

import {
  ReactFlow,
  Controls,
  Background,
  useNodesState,
  useEdgesState,
  addEdge,
  MarkerType,
  Panel,
} from '@xyflow/react';
import type { Node, Edge, Connection } from '@xyflow/react';
import { Plus, Save, Trash2, User, MapPin, Shield, Gem } from 'lucide-react';
import { useCallback, useEffect, useState } from 'react';

import '@xyflow/react/dist/style.css';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { useNovelQuery, useRelationshipsQuery, useAddRelationshipMutation, useDeleteRelationshipMutation, useGraphLayoutQuery, useSaveGraphLayoutMutation } from '@/core/novel/queries';
import type { EntityRelationship, GraphLayout } from '@/core/novel/schemas';

const ENTITY_COLORS: Record<string, string> = {
  character: '#3b82f6',
  setting: '#22c55e',
  faction: '#ef4444',
  item: '#a855f7',
};

const RELATIONSHIP_COLORS: Record<string, string> = {
  friend: '#22c55e',
  enemy: '#ef4444',
  family: '#f59e0b',
  lover: '#ec4899',
  custom: '#6b7280',
};

function getNodeIcon(type: string) {
  switch (type) {
    case 'character': return <User className="h-4 w-4" />;
    case 'setting': return <MapPin className="h-4 w-4" />;
    case 'faction': return <Shield className="h-4 w-4" />;
    case 'item': return <Gem className="h-4 w-4" />;
    default: return null;
  }
}

function CustomNode({ data }: { data: { label: string; type: string; description?: string } }) {
  const color = ENTITY_COLORS[data.type] || '#6b7280';
  return (
    <Card className="min-w-[150px] border-2" style={{ borderColor: color }}>
      <CardContent className="p-3 text-center">
        <div className="flex items-center justify-center gap-2 mb-1">
          {getNodeIcon(data.type)}
          <span className="font-medium text-sm">{data.label}</span>
        </div>
        <Badge variant="outline" className="text-xs" style={{ borderColor: color, color }}>
          {data.type}
        </Badge>
      </CardContent>
    </Card>
  );
}

const nodeTypes = { custom: CustomNode };

interface RelationshipGraphProps {
  novelId: string;
}

export function RelationshipGraph({ novelId }: RelationshipGraphProps) {
  const { data: novel } = useNovelQuery(novelId);
  const { data: relationships } = useRelationshipsQuery(novelId);
  const { data: savedLayout } = useGraphLayoutQuery(novelId);
  const saveLayout = useSaveGraphLayoutMutation();
  const [nodes, setNodes, onNodesChange] = useNodesState<Node>([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState<Edge>([]);
  const [showAddDialog, setShowAddDialog] = useState(false);
  const [sourceId, setSourceId] = useState('');
  const [targetId, setTargetId] = useState('');
  const [relType, setRelType] = useState<EntityRelationship['type']>('friend');
  const [relDescription, setRelDescription] = useState('');
  const [hasLayoutChanges, setHasLayoutChanges] = useState(false);

  const addRelationship = useAddRelationshipMutation(novelId);
  const deleteRelationship = useDeleteRelationshipMutation();

  const handleNodeDragStop = useCallback((_event: any, node: Node) => {
    setNodes((nds) => nds.map((n) => (n.id === node.id ? { ...n, position: node.position } : n)));
    setHasLayoutChanges(true);
  }, [setNodes]);

  const handleSaveLayout = useCallback(async () => {
    if (!novelId || nodes.length === 0) return;
    const positions: Record<string, { x: number; y: number }> = {};
    nodes.forEach((n) => {
      positions[n.id] = n.position;
    });

    const layout: GraphLayout = {
      id: `layout-${novelId}`,
      novelId,
      nodePositions: positions,
      isLocked: false,
      lastUpdated: new Date(),
    };

    await saveLayout.mutateAsync(layout);
    setHasLayoutChanges(false);
  }, [novelId, nodes, saveLayout]);

  useEffect(() => {
    if (!novel) return;

    const allEntities = [
      ...(novel.characters || []).map((c) => ({ ...c, entityType: 'character' as const })),
      ...(novel.settings || []).map((s) => ({ ...s, entityType: 'setting' as const })),
      ...(novel.factions || []).map((f) => ({ ...f, entityType: 'faction' as const })),
      ...(novel.items || []).map((i) => ({ ...i, entityType: 'item' as const })),
    ];

    const savedPositions = savedLayout?.nodePositions || {};

    const nodeData: Node[] = allEntities.map((entity, index) => {
      const savedPos = savedPositions[entity.id];
      if (savedPos) {
        return {
          id: entity.id,
          type: 'custom',
          position: savedPos,
          data: {
            label: entity.name,
            type: entity.entityType,
            description: entity.description,
          },
        };
      }

      const angle = (index / allEntities.length) * 2 * Math.PI;
      const radius = 300;
      return {
        id: entity.id,
        type: 'custom',
        position: { x: Math.cos(angle) * radius + 400, y: Math.sin(angle) * radius + 300 },
        data: {
          label: entity.name,
          type: entity.entityType,
          description: entity.description,
        },
      };
    });

    setNodes(nodeData);

    const edgeData: Edge[] = (relationships || []).map((rel) => ({
      id: rel.id,
      source: rel.sourceId,
      target: rel.targetId,
      label: rel.description || rel.type,
      style: { stroke: RELATIONSHIP_COLORS[rel.type] || '#6b7280', strokeWidth: 2 },
      markerEnd: { type: MarkerType.ArrowClosed, color: RELATIONSHIP_COLORS[rel.type] || '#6b7280' },
    }));

    setEdges(edgeData);
  }, [novel, relationships, savedLayout]);

  const onConnect = useCallback(
    (params: Connection) => setEdges((eds) => addEdge(params, eds)),
    [setEdges]
  );

  const handleAddRelationship = async () => {
    if (!sourceId || !targetId || !novelId) return;
    await addRelationship.mutateAsync({
      id: crypto.randomUUID(),
      sourceId,
      targetId,
      type: relType,
      description: relDescription,
      novelId,
    });
    setShowAddDialog(false);
    setSourceId('');
    setTargetId('');
    setRelType('friend');
    setRelDescription('');
  };

  const handleDeleteRelationship = async (edgeId: string) => {
    if (confirm('Delete this relationship?')) {
      await deleteRelationship.mutateAsync(edgeId);
    }
  };

  if (!novel) {
    return <div className="flex h-full items-center justify-center text-muted-foreground">Loading...</div>;
  }

  const allEntities = [
    ...(novel.characters || []),
    ...(novel.settings || []),
    ...(novel.factions || []),
    ...(novel.items || []),
  ];

  return (
    <div className="h-full w-full">
      <ReactFlow
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        onNodeDragStop={handleNodeDragStop}
        nodeTypes={nodeTypes}
        fitView
        className="bg-muted/20"
      >
        <Background />
        <Controls />
        <Panel position="top-left">
          <div className="bg-background rounded-lg shadow-lg p-2 border">
            <h3 className="text-sm font-medium mb-2">Entity Relationships</h3>
            <Button size="sm" className="gap-1 w-full" onClick={() => setShowAddDialog(true)}>
              <Plus className="h-3 w-3" />
              Add Relationship
            </Button>
          </div>
        </Panel>
        {hasLayoutChanges && (
          <Panel position="top-right">
            <Button size="sm" className="gap-1" onClick={handleSaveLayout} disabled={saveLayout.isPending}>
              <Save className="h-3 w-3" />
              {saveLayout.isPending ? '保存中...' : '保存布局'}
            </Button>
          </Panel>
        )}
        <Panel position="bottom-right">
          <div className="bg-background rounded-lg shadow-lg p-2 border text-xs space-y-1">
            {Object.entries(ENTITY_COLORS).map(([type, color]) => (
              <div key={type} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: color }} />
                <span className="capitalize">{type}</span>
              </div>
            ))}
          </div>
        </Panel>
      </ReactFlow>

      <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Add Relationship</DialogTitle>
            <DialogDescription>Create a connection between two entities.</DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Source Entity</Label>
              <Select value={sourceId} onValueChange={setSourceId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select source..." />
                </SelectTrigger>
                <SelectContent>
                  {allEntities.map((entity) => (
                    <SelectItem key={entity.id} value={entity.id}>
                      {entity.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Target Entity</Label>
              <Select value={targetId} onValueChange={setTargetId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select target..." />
                </SelectTrigger>
                <SelectContent>
                  {allEntities.map((entity) => (
                    <SelectItem key={entity.id} value={entity.id}>
                      {entity.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Relationship Type</Label>
              <Select value={relType} onValueChange={(v) => setRelType(v as any)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="friend">Friend</SelectItem>
                  <SelectItem value="enemy">Enemy</SelectItem>
                  <SelectItem value="family">Family</SelectItem>
                  <SelectItem value="lover">Lover</SelectItem>
                  <SelectItem value="custom">Custom</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Description (optional)</Label>
              <input
                type="text"
                className="flex h-9 w-full rounded-md border bg-transparent px-3 py-1 text-sm"
                value={relDescription}
                onChange={(e) => setRelDescription(e.target.value)}
                placeholder="Describe the relationship..."
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowAddDialog(false)}>
              Cancel
            </Button>
            <Button onClick={handleAddRelationship} disabled={!sourceId || !targetId}>
              Create
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

