              <Textarea
                placeholder="描述你的任务，例如: '帮我补全第三章的伏笔，主角在地下室发现的信件应该在后续章节中发挥作用'..."
                value={aiTaskPrompt}
                onChange={(e) => setAiTaskPrompt(e.target.value)}
