                    step={1}
                    className="flex-1"
                  />
                  <Button variant="ghost" size="icon" onClick={() => setFontSize((v) => Math.min(32, v + 1))}>
                    <Plus className="h-3 w-3" />
                  </Button>
                  <span className="text-sm w-8 text-right">{fontSize}</span>
                </div>
              </div>

              <div>
                <label className="text-sm font-medium mb-2 block">行高</label>
