            >
              {paragraphs.length > 0 ? (
                paragraphs.map((p, i) => (
                  <p
                    key={i}
                    style={{
                      marginBottom: `${paragraphSpacing}px`,
                      textIndent: '2em',
                      opacity: focusMode ? (i === 0 ? 1 : 0.3) : 1,
