                    {p}
                  </p>
                ))
              ) : (
                <p style={{ color: themeColors.secondary }}>暂无内容</p>
              )}
            </div>
          </article>
        </main>

        {/* Chapter list sidebar */}
        {!isImmersive && chapters.length > 5 && (
          <aside
