    });
    setShowCreate(false);
  };

  const handleDelete = async (eventId: string) => {
    if (confirm('Delete this timeline event?')) {
      await deleteMutation.mutateAsync(eventId);
    }
  };

  return (
    <div className="flex h-full flex-col">
      <div className="border-b p-4 flex items-center justify-between">
        <h2 className="text-lg font-semibold flex items-center gap-2">
          <Calendar className="h-5 w-5" />
          Timeline
        </h2>
        <Button
          variant="outline"
          size="sm"
          className="gap-1"
          onClick={() => setShowCreate(true)}
        >
          <Plus className="h-3 w-3" />
          Add Event
        </Button>
      </div>

      <ScrollArea className="flex-1">
        <div className="p-4">
          {!events || events.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              No timeline events yet. Click &quot;Add Event&quot; to create one.
            </div>
          ) : (
            <div className="relative">
              <div className="absolute left-4 top-0 bottom-0 w-px bg-border" />
              <div className="space-y-4 pl-8">
                {events.map((event) => (
                  <TimelineEventCard
                    key={event.id}
                    event={event}
                    onDelete={handleDelete}
                    onEdit={() => setEditingEvent(event)}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      </ScrollArea>

      <TimelineEventDialog
        open={showCreate}
        onOpenChange={setShowCreate}
        onSubmit={handleCreate}
      />
    </div>
  );
}

function TimelineEventCard({
  event,
  onDelete,
  onEdit,
}: {
  event: TimelineEvent;
  onDelete: (id: string) => void;
  onEdit: () => void;
}) {
  const typeColors: Record<string, string> = {
    backstory: 'bg-blue-500/10 text-blue-500 border-blue-500/20',
    plot: 'bg-green-500/10 text-green-500 border-green-500/20',
    historical: 'bg-purple-500/10 text-purple-500 border-purple-500/20',
  };

  return (
    <Card className="relative">
      <div className="absolute -left-8 top-4 h-3 w-3 rounded-full bg-primary ring-4 ring-background" />
      <CardHeader className="pb-2">
        <div className="flex items-start justify-between">
          <div className="space-y-1">
            <CardTitle className="text-base">{event.title}</CardTitle>
            <div className="flex items-center gap-2 text-xs text-muted-foreground">
              <Clock className="h-3 w-3" />
              {event.dateDisplay}
            </div>
          </div>
          <div className="flex items-center gap-2">
            <Badge
              variant="outline"
              className={typeColors[event.type] || ''}
            >
              {event.type}
            </Badge>
            <Button
              variant="ghost"
              size="sm"
              className="h-6 w-6 p-0"
              onClick={onEdit}
            >
              <Edit className="h-3 w-3" />
            </Button>
            <Button
              variant="ghost"
              size="sm"
              className="h-6 w-6 p-0 text-destructive hover:text-destructive"
              onClick={() => onDelete(event.id)}
            >
              <Trash2 className="h-3 w-3" />
            </Button>
          </div>
        </div>
      </CardHeader>
      {event.description && (
        <CardContent className="pt-0 text-sm text-muted-foreground">
          {event.description}
        </CardContent>
      )}
    </Card>
  );
}

function TimelineEventDialog({
  open,
  onOpenChange,
  onSubmit,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSubmit: (data: any) => void;
}) {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [dateDisplay, setDateDisplay] = useState('');
  const [sortValue, setSortValue] = useState(0);
  const [type, setType] = useState<'backstory' | 'plot' | 'historical'>('plot');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit({
      title,
      description,
      dateDisplay,
      sortValue,
      type,
    });
    setTitle('');
    setDescription('');
    setDateDisplay('');
    setSortValue(0);
    setType('plot');
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <form onSubmit={handleSubmit}>
          <DialogHeader>
            <DialogTitle>Add Timeline Event</DialogTitle>
            <DialogDescription>
              Create a new event in your story timeline.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="title">Event Title</Label>
              <Input
                id="title"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="dateDisplay">Time Display</Label>
              <Input
                id="dateDisplay"
                placeholder="e.g., Empire Year 305"
                value={dateDisplay}
                onChange={(e) => setDateDisplay(e.target.value)}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="sortValue">Sort Value (Year * 100)</Label>
              <Input
                id="sortValue"
                type="number"
                value={sortValue}
                onChange={(e) => setSortValue(Number(e.target.value))}
                required
              />
            </div>
            <div className="space-y-2">
              <Label>Type</Label>
              <Select value={type} onValueChange={(v: any) => setType(v)}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="plot">Plot</SelectItem>
                  <SelectItem value="backstory">Backstory</SelectItem>
                  <SelectItem value="historical">Historical</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="description">Description</Label>
              <Textarea
                id="description"
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                rows={3}
              />
            </div>
          </div>
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
              Cancel
            </Button>
            <Button type="submit">Create</Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { create } from "zustand";

import type { OutlineNode } from "./schemas";

interface OutlineState {
  tree: OutlineNode[];
  isGenerating: boolean;
  selectedNodeId: string | null;

  setTree: (nodes: OutlineNode[]) => void;
  updateNode: (id: string, data: Partial<OutlineNode>) => void;
  updateNodeStatus: (id: string, status: "idle" | "generating" | "error") => void;
  toggleSelection: (id: string) => void;
  selectAll: () => void;
  deselectAll: () => void;
  addNode: (node: OutlineNode, parentId?: string) => void;
  removeNode: (id: string) => void;
  setSelectedNode: (id: string | null) => void;
  setIsGenerating: (generating: boolean) => void;
  clearTree: () => void;
  moveNode: (activeId: string, overId: string) => void;
  updateNodeIds: (idMap: Record<string, string>) => void;
}

function arrayMove<T>(array: T[], from: number, to: number): T[] {
  const newArray = [...array];
  const [item] = newArray.splice(from, 1);
  newArray.splice(to, 0, item!);
  return newArray;
}

export const useOutlineStore = create<OutlineState>()((set, get) => ({
  tree: [],
  isGenerating: false,
  selectedNodeId: null,

  setTree: (nodes) => set({ tree: nodes }),

  updateNode: (id, data) => {
    const updateNodeRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes.map((node) => {
        if (node.id === id) {
          return { ...node, ...data };
        }
        if (node.children) {
          return { ...node, children: updateNodeRecursive(node.children) };
        }
        return node;
      });
    };
    set((state) => ({ tree: updateNodeRecursive(state.tree) }));
  },

  updateNodeStatus: (id, status) => {
    const updateStatusRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes.map((node) => {
        if (node.id === id) {
          return { ...node, status };
        }
        if (node.children) {
          return { ...node, children: updateStatusRecursive(node.children) };
        }
        return node;
      });
    };
    set((state) => ({ tree: updateStatusRecursive(state.tree) }));
  },

  toggleSelection: (id) => {
    const toggleNodeRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes.map((node) => {
        if (node.id === id) {
          return { ...node, isSelected: !node.isSelected };
        }
        if (node.children) {
          return { ...node, children: toggleNodeRecursive(node.children) };
        }
        return node;
      });
    };
    set((state) => ({ tree: toggleNodeRecursive(state.tree) }));
  },

  selectAll: () => {
    const selectAllRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes.map((node) => ({
        ...node,
        isSelected: true,
        children: node.children ? selectAllRecursive(node.children) : undefined,
      }));
    };
    set((state) => ({ tree: selectAllRecursive(state.tree) }));
  },

  deselectAll: () => {
    const deselectAllRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes.map((node) => ({
        ...node,
        isSelected: false,
        children: node.children ? deselectAllRecursive(node.children) : undefined,
      }));
    };
    set((state) => ({ tree: deselectAllRecursive(state.tree) }));
  },

  addNode: (node, parentId) => {
    if (!parentId) {
      set((state) => ({ tree: [...state.tree, node] }));
    } else {
      const addNodeRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
        return nodes.map((n) => {
          if (n.id === parentId) {
            return { ...n, children: [...(n.children || []), node] };
          }
          if (n.children) {
            return { ...n, children: addNodeRecursive(n.children) };
          }
          return n;
        });
      };
      set((state) => ({ tree: addNodeRecursive(state.tree) }));
    }
  },

  removeNode: (id) => {
    const removeNodeRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes
        .filter((node) => node.id !== id)
        .map((node) => ({
          ...node,
          children: node.children ? removeNodeRecursive(node.children) : undefined,
        }));
    };
    set((state) => ({ tree: removeNodeRecursive(state.tree) }));
  },

  setSelectedNode: (id) => set({ selectedNodeId: id }),
  setIsGenerating: (generating) => set({ isGenerating: generating }),
  clearTree: () => set({ tree: [], selectedNodeId: null }),

  moveNode: (activeId, overId) => {
    set((state) => {
      const deepClone = JSON.parse(JSON.stringify(state.tree));

      const activeIndexRoot = deepClone.findIndex((n: OutlineNode) => n.id === activeId);
      const overIndexRoot = deepClone.findIndex((n: OutlineNode) => n.id === overId);

      if (activeIndexRoot !== -1 && overIndexRoot !== -1) {
        return { tree: arrayMove(deepClone, activeIndexRoot, overIndexRoot) };
      }

      for (const vol of deepClone) {
        if (vol.children) {
          const activeIndex = vol.children.findIndex((n: OutlineNode) => n.id === activeId);
          const overIndex = vol.children.findIndex((n: OutlineNode) => n.id === overId);

          if (activeIndex !== -1 && overIndex !== -1) {
            vol.children = arrayMove(vol.children, activeIndex, overIndex);
            return { tree: deepClone };
          }
        }
      }

      return { tree: state.tree };
    });
  },

  updateNodeIds: (idMap) => {
    const updateIdsRecursive = (nodes: OutlineNode[]): OutlineNode[] => {
      return nodes.map((node) => {
        const updatedNode = { ...node };
        const mappedId = idMap[node.id];
        if (mappedId !== undefined) {
          updatedNode.id = mappedId;
        }
        if (node.children) {
          updatedNode.children = updateIdsRecursive(node.children);
        }
        return updatedNode;
      });
    };
    set((state) => ({ tree: updateIdsRecursive(state.tree) }));
  },
}));
